/**
 * Stub mínimo para que TypeScript no se queje del import dinámico
 * de @google/model-viewer cuando el paquete todavía no fue instalado.
 *
 * Cuando se corre `npm install --legacy-peer-deps`, las tipings reales
 * del paquete sobreescriben este stub automáticamente.
 */
declare module '@google/model-viewer';
